<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;5. Keep SKILL.md under 500 lines — put details in references/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
